// ==========================================
// 0. SISTEMA SRE DE IDEMPOTÊNCIA (ANTI-DUPLICADOS)
// ==========================================
// Cria uma assinatura única para o e-mail
const emailSignature = msg.messageId || (msg.topic + "_" + msg.date);

// Vai buscar a memória de e-mails já processados (Cache)
let processedEmails = flow.get("processedEmailsCache") || [];

// Se a assinatura já existir na memória, bloqueia e descarta!
if (processedEmails.includes(emailSignature)) {
    node.warn("🛡️ Intercetado: E-mail duplicado bloqueado pelo sistema (" + msg.topic + ")");
    return [null, null]; // Interrompe o fluxo completamente
}

// Se for um e-mail novo, regista a assinatura na memória
processedEmails.push(emailSignature);
if (processedEmails.length > 50) {
    processedEmails.shift(); // Remove os registos mais antigos para não sobrecarregar a memória RAM
}
flow.set("processedEmailsCache", processedEmails);


// ==========================================
// 1. Captura e tratamento seguro dos dados brutos
// ==========================================
// ... (mantenha todo o seu código original a partir daqui)
const assunto = (msg.topic || "").toLowerCase();
let corpo = "";


try {
    if (msg.payload) {
        if (typeof msg.payload === 'string') {
            corpo = msg.payload;
        } else if (Buffer.isBuffer(msg.payload)) {
            corpo = msg.payload.toString('utf8');
        } else {
            corpo = JSON.stringify(msg.payload);
        }
    }
} catch (error) {
    node.warn("Aviso: Falha ao extrair corpo do e-mail. Erro: " + error.message);
    corpo = "";
}

// Limpa o HTML para a busca
corpo = corpo.replace(/(<([^>]+)>)/gi, " ").toLowerCase();

// Pega o e-mail do remetente e deixa minúsculo para a Blacklist
const remetente = (msg.from || "Desconhecido").toLowerCase();
const data = new Date().toLocaleString('pt-BR');

// ==========================================
// NOVA ENGENHARIA DE FILTROS 
// ==========================================

// 2. FILTRO NEGATIVO (A "Blacklist")
// Mata o fluxo IMEDIATAMENTE se for marketing, newsletter ou alerta genérico
const keywordsIgnorar = ["alerta de vaga", "vaga nova", "novas vagas", "newsletter", "dicas", "boas vindas", "bem-vindo", "promoção", "oferta", "natal", "black friday"];
const remetentesIgnorar = ["news@", "sucessodoaluno@", "listings@", "newsletter@", "relacionamento@", "read@", "itaucard@", "weekender@", "cruzeirodosulvirtual@", "noreply@", "hello@", "system@", "linkedin@","dicas@", "marketing@", "info@", "contato@", "hello@sendgrid"];

const isBlacklisted = 
    keywordsIgnorar.some(kw => assunto.includes(kw)) || 
    remetentesIgnorar.some(rem => remetente.includes(rem));

if (isBlacklisted) {
    // É lixo/marketing. Retorna nulo e encerra a execução deste e-mail.
    return [null, null]; 
}

// 3. FILTRO POSITIVO (A "Whitelist" Refinada)
// Removemos a palavra "vaga" solta no corpo. Focamos em jargões de ATS e RH.
const keywordsVaga = [
    "candidatura", "candidatou-se", "processo seletivo", 
    "agradecemos seu interesse", "agradecemos sua candidatura", 
    "status da sua aplicação", "application status", "application received"
];

// Regra de Ouro: Só aceitamos a palavra "vaga" se ela estiver no ASSUNTO. 
// Se estiver perdida no meio do corpo, ignoramos.
const isEmprego = keywordsVaga.some(kw => assunto.includes(kw) || corpo.includes(kw)) || assunto.includes("vaga");

if (isEmprego) {
    let status = "Neutro / Recebido";
    let tipoAlerta = "info";

    const keywordsPositivo = ["entrevista", "interview", "próxima etapa", "next steps", "convite", "proposta", "offer", "parabéns", "congratulations", "bate-papo", "bate papo", "avaliação"];
    const keywordsNegativo = ["infelizmente", "unfortunately", "não seguiremos", "outros candidatos", "other candidates", "not selected", "not moving forward"];

    if (keywordsNegativo.some(kw => assunto.includes(kw) || corpo.includes(kw))) {
        status = "❌ Declinado";
        tipoAlerta = "negativo";
    } else if (keywordsPositivo.some(kw => assunto.includes(kw) || corpo.includes(kw))) {
        status = "✅ Avanço / Entrevista!";
        tipoAlerta = "positivo";
    }

    const novaVaga = {
        id: Date.now(),
        dataOriginal: msg.date.toLocaleString('pt-BR'),
        processadoEm: data,
        remetente: msg.from.replace(/<.*>/, '').trim(), // Limpa o nome na hora de mostrar
        assunto: msg.topic || "Sem Assunto",
        status: status,
        tipo: tipoAlerta
    };

    let historico = flow.get("historicoVagas") || [];
    historico.unshift(novaVaga);
    if (historico.length > 50) { historico.pop(); }
    flow.set("historicoVagas", historico);

    return [{ payload: historico }, { payload: novaVaga }, { payload: novaVaga }];
}

// Se não for e-mail de emprego, morre aqui
return [null, null];

const vaga = msg.payload;

// TRAVA DE SEGURANÇA: Se não for um objeto válido, morre aqui e não aciona o exec
if (!vaga || !vaga.tipo) {
    return null; 
}

let som = "afplay /System/Library/Sounds/Glass.aiff";

if (vaga.tipo === "positivo") {
    som = `afplay /System/Library/Sounds/Hero.aiff && say -v Luciana "Atenção. Você recebeu um e-mail de entrevista de ${vaga.remetente}"`;
} 
else if (vaga.tipo === "negativo") {
    som = `afplay /System/Library/Sounds/Basso.aiff`;
}

msg.payload = som;
return msg;

const vaga = msg.payload;

// Só manda para o Telegram se for um avanço/entrevista (evita flood no celular)
if (vaga.tipo !== "positivo") {
    return null;
}

// Formata a mensagem usando emojis e quebras de linha
const textoTelegram = `
🎉 *Boas Notícias!*
Você tem uma atualização de processo seletivo.

🏢 *De:* ${vaga.remetente}
📌 *Assunto:* ${vaga.assunto}
📆 *Data:* ${vaga.date}

Vá para o seu Dashboard ou cheque o e-mail para mais detalhes!
`;

// O nó do Telegram exige que a mensagem seja passada dentro de msg.payload.content
msg.payload = {
    chatId: 6909201684,
    type: "message",
    content: textoTelegram,
    options: { parse_mode: "Markdown" } // Permite usar negrito com asteriscos
};

return msg;
